func capPeriodLabel(p *string) string {
	if p == nil || *p == "" {
		return ""
	}
	if *p == "monthly" {
		return "/mo"
	}
	return "/yr"
}

func utilizationPct(balance, limit float64) float64 {
	if limit <= 0 {
		return 0
	}
	return (balance / limit) * 100
}

func utilColor(pct float64) string {
	if pct >= 70 {
		return "var(--red)"
	}
	if pct >= 30 {
		return "var(--yellow)"
	}
	return "var(--green)"
}

func daysUntil(dateStr string) int {
	t, err := time.Parse("2006-01-02", dateStr)
	if err != nil {
		return 999
	}
	now := time.Now().UTC()
	today := time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, time.UTC)
	due := time.Date(t.Year(), t.Month(), t.Day(), 0, 0, 0, 0, time.UTC)
	return int(due.Sub(today).Hours() / 24)
}

func daysLabel(days int) string {
	if days < 0 {
		return fmt.Sprintf("%d days overdue", -days)
	}
	if days == 0 {
		return "due today"
	}
	if days == 1 {
		return "tomorrow"
	}
	return fmt.Sprintf("in %d days", days)
}

func dueDateColor(days int) string {
	if days < 0 {
		return "var(--red)"
	}
	if days <= 7 {
		return "var(--red)"
	}
	if days <= 14 {
		return "var(--yellow)"
	}
	return "var(--text)"
}

func formatCardDate(dateStr string) string {
	t, err := time.Parse("2006-01-02", dateStr)
	if err != nil {
		return dateStr
	}
	return t.Format("Jan 2")
}

